class KafkaTransactionConsumer:
    def __init__(self, bootstrap_servers, topics, group_id, processor_instance):
        self.bootstrap_servers = bootstrap_servers
        self.topics = topics
        self.group_id = group_id
        self.processor = processor_instance
        self.consumer = None
        self._running = True

    def _deserialize_message(self, message_value):
        """
        Deserializes the message value from bytes to a Python dictionary.
        Assumes JSON serialization.
        """
        try:
            return json.loads(message_value.decode('utf-8'))
        except json.JSONDecodeError as e:
            logger.error(f"Failed to deserialize message: {message_value}. Error: {e}")
            return None
        except UnicodeDecodeError as e:
            logger.error(f"Failed to decode message bytes: {message_value}. Error: {e}")
            return None

    def _execute_business_logic(self, transaction_event):
        """
        Dynamically calls the appropriate handler method based on 'transaction_type'.
        """
        transaction_type = transaction_event.get('transaction_type')
        if not transaction_type:
            logger.warning(f"Message missing 'transaction_type': {transaction_event}. Skipping.")
            return {"status": "error", "message": "Missing transaction_type"}

        # Method names are expected to be 'process_<transaction_type_lowercase>'
        handler_method_name = f"process_{transaction_type.lower()}"
        handler = getattr(self.processor, handler_method_name, None)

        if handler:
            try:
                logger.info(f"Executing handler '{handler_method_name}' for transaction ID: {transaction_event.get('transaction_id')}")
                result = handler(transaction_event)
                logger.info(f"Handler '{handler_method_name}' result: {result}")
                return result
            except Exception as e:
                logger.error(f"Error executing handler '{handler_method_name}' for transaction {transaction_event.get('transaction_id')}: {e}", exc_info=True)
                return {"status": "error", "message": f"Handler execution failed: {e}"}
        else:
            logger.warning(f"No handler found for transaction type '{transaction_type}'. Skipping transaction ID: {transaction_event.get('transaction_id')}")
            return {"status": "error", "message": f"No handler for type: {transaction_type}"}

    def connect_consumer(self):
        """Establishes connection to Kafka."""
        while self._running:
            try:
                self.consumer = KafkaConsumer(
                    *self.topics,
                    bootstrap_servers=self.bootstrap_servers,
                    group_id=self.group_id,
                    auto_offset_reset='earliest',  # Start from the beginning if no offset is committed
                    enable_auto_commit=True,       # Automatically commit offsets
                    auto_commit_interval_ms=5000,  # Commit every 5 seconds
                    value_deserializer=None,       # We will deserialize manually
                    max_poll_records=500,          # Max records to fetch in a single poll
                    session_timeout_ms=10000,      # Consumer session timeout
                    heartbeat_interval_ms=3000     # Heartbeat interval
                )
                logger.info(f"Kafka consumer connected to {self.bootstrap_servers} for topics {self.topics} with group_id {self.group_id}")
                return True
            except NoBrokersAvailable:
                logger.warning(f"No Kafka brokers available at {self.bootstrap_servers}. Retrying in 5 seconds...")
                time.sleep(5)
            except KafkaError as e:
                logger.error(f"Kafka connection error: {e}. Retrying in 5 seconds...", exc_info=True)
                time.sleep(5)
            except Exception as e:
                logger.error(f"An unexpected error occurred during Kafka connection: {e}. Retrying in 5 seconds...", exc_info=True)
                time.sleep(5)
        return False

    def consume_messages(self):
        """
        Continuously polls Kafka for new messages and processes them.
        """
        if not self.consumer and not self.connect_consumer():
            logger.error("Failed to connect to Kafka. Exiting consumer.")
            return

        logger.info("Starting to consume messages...")
        try:
            while self._running:
                messages = self.consumer.poll(timeout_ms=1000) # Poll for messages with a timeout
                if not messages:
                    # logger.debug("No messages received, polling again...")
                    continue

                for topic_partition, records in messages.items():
                    for record in records:
                        logger.debug(f"Received message from topic: {record.topic}, partition: {record.partition}, offset: {record.offset}")
                        transaction_event = self._deserialize_message(record.value)

                        if transaction_event:
                            self._execute_business_logic(transaction_event)
                        else:
                            logger.error(f"Skipping message at offset {record.offset} due to deserialization failure.")
                # Offsets are auto-committed if enable_auto_commit is True
        except KeyboardInterrupt:
            logger.info("Consumer stopped by user (KeyboardInterrupt).")
        except KafkaError as e:
            logger.error(f"Kafka consumer error: {e}", exc_info=True)
        except Exception as e:
            logger.error(f"An unexpected error occurred during message consumption: {e}", exc_info=True)
        finally:
            self.close()

    def close(self):
        """Closes the Kafka consumer."""
        self._running = False
        if self.consumer:
            self.consumer.close()
            logger.info("Kafka consumer closed.")

